using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Adjust the namespace according to your project
using System.Web.Security;

public class ReviewsController : Controller
{
    private YourDbContext db = new YourDbContext(); // Replace with your actual DbContext

    [HttpGet]
    public ActionResult Index(int productId)
    {
        var reviews = db.Reviews.Where(r => r.ProductId == productId).ToList();
        return View(reviews);
    }

    [HttpPost]
    [Authorize]
    public ActionResult SubmitReview(int productId, string reviewText)
    {
        if (string.IsNullOrWhiteSpace(reviewText))
        {
            ModelState.AddModelError("ReviewText", "Review cannot be empty.");
            return RedirectToAction("Index", new { productId });
        }

        var review = new Review
        {
            ProductId = productId,
            UserId = User.Identity.GetUserId(), // Assuming you're using Identity
            ReviewText = reviewText,
            CreatedAt = DateTime.Now
        };

        db.Reviews.Add(review);
        db.SaveChanges();

        return RedirectToAction("Index", new { productId });
    }
}

// Razor View (Index.cshtml)
@model IEnumerable<YourNamespace.Models.Review>

<h2>Product Reviews</h2>

@using (Html.BeginForm("SubmitReview", "Reviews", FormMethod.Post))
{
    @Html.Hidden("productId", ViewBag.ProductId)
    <div>
        @Html.TextArea("reviewText", null, new { @placeholder = "Write your review here...", @rows = 5 })
        <button type="submit">Submit Review</button>
    </div>
}

<ul>
    @foreach (var review in Model)
    {
        <li>
            @Html.Raw(review.ReviewText) - @Html.DisplayFor(m => review.CreatedAt)
        </li>
    }
</ul>